VALUES
  ('optometrist-moex-02494', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關配戴隱形眼鏡引起的併發症角膜混濁（corneal haze）之敘述，下列何者錯誤？', '["常見於配戴低透氧硬式隱形眼鏡或PMMA隱形眼鏡", "使用裂隙燈檢查，可發現角膜中央有明顯的基質層水腫（stromal edema）", "因長期的角膜缺氧（corneal hypoxia），會引起輪部（limbus）外的血管向角膜內生長", "裂隙燈觀察到角膜中央區會有淡棕色的霧狀外觀"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "81a695067d45", "answer_pdf_sha1": "16b4ed929ce6", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02495', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '不同隱形眼鏡引起的感染性角膜潰瘍，其發生率由高至低排列，應為下列何者？①透氣硬式隱形', '["日戴軟式隱形眼鏡", "過夜配戴軟式隱形眼鏡", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "81a695067d45", "answer_pdf_sha1": "16b4ed929ce6", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02496', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關配戴鞏膜鏡後常見的鏡片下殘渣（reservoir debris）何者錯誤？', '["成分可以包含很多東西，但通常是黏液、上皮細胞、甚至化妝品", "乾眼症患者的這種情況會更嚴重", "可能會造成視力模糊，因此遇到此狀況時需將鏡片摘下清洗並重新潤濕戴回", "較大直徑的鞏膜片比較不會產生這種情形"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "81a695067d45", "answer_pdf_sha1": "16b4ed929ce6", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02497', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '一位配戴軟式隱形眼鏡者回診，配戴期間並無定期更換，自覺眼癢及睡醒時分泌物增加，回診檢查 發現有二度結膜乳突形成且鏡片中度沉澱包覆（lens deposition coating），下列敘述何者錯誤？', '["該患者有巨大乳突結膜炎（giant papilla conjunctivitis）", "軟式隱形眼鏡鏡片清洗後可繼續配戴", "再教導正確鏡片清洗方法", "可改用日拋型軟式隱形眼鏡（daily disposable lens）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "81a695067d45", "answer_pdf_sha1": "16b4ed929ce6", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02498', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '老花患者長期配戴框架眼鏡且對遠用視力的品質要求極高，想要配戴老花同步視覺多焦點 （simultaneous-vision multifocal）隱形眼鏡後讓生活更便利，因此他也非常想要配戴。您可運用何種 檢測方式來比較框架眼鏡及隱形眼鏡的視覺表現，以提供您此老花隱形眼鏡驗配之成功與否的訊 息？', '["進行紅綠測試來比較框架眼鏡及隱形眼鏡的紅綠清晰度是否相近", "進行融像交叉圓柱鏡測試來比較框架眼鏡及隱形眼鏡的橫與直線清晰度是否相近", "進行高對比與低對比的視力檢測來比較框架眼鏡及隱形眼鏡的的視力表現是否相近", "進行針孔測試來比較框架眼鏡及隱形眼鏡的針孔視力是否相近"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "81a695067d45", "answer_pdf_sha1": "16b4ed929ce6", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02499', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關同步視覺設計之老花隱形眼鏡，下列敘述何者錯誤？', '["驗配成功率高", "配戴者之瞳孔大小影響很大", "鏡片之旋轉穩定度（rotation stability）比置中性（centration）重要", "維持立體視覺"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "81a695067d45", "answer_pdf_sha1": "16b4ed929ce6", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02500', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '根據Richdale（2006）的研究，關於鏡框眼鏡，單眼視覺法隱形眼鏡，同步視覺中央視近隱形眼鏡三 種方法驗配老花眼，對於低對比度（low-contrast）之遠視力影響，下列敍述何者正確？', '["鏡框眼鏡影響最大", "單眼視覺法隱形眼鏡影響最大", "同步視覺中央視近隱形眼鏡影響最大", "三者表現相當"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "81a695067d45", "answer_pdf_sha1": "16b4ed929ce6", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02501', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '因考慮角膜及鞏膜曲度不同，軟式隱形眼鏡的設計概念，下列敘述何者正確？', '["鏡片中央較角膜中心為平，往外稍陡，周邊又變平", "鏡片中央較角膜中心為陡，往外更陡，周邊又變平", "鏡片中央較角膜中心為平，往外稍陡，周邊又更陡", "鏡片中央較角膜中心為平，往外更平，周邊又更平"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "81a695067d45", "answer_pdf_sha1": "16b4ed929ce6", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02502', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '散光軟式隱形眼鏡需有良好的定位避免鏡片旋轉，才能得到散光矯正效果，下列何者為目前最常用 的穩定設計方式？', '["鏡片前表面複曲面設計（toric frontal surface）", "稜鏡垂重（prism ballast）", "下緣切除型（truncation）", "動態穩定設計（dynamic stabilization）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "81a695067d45", "answer_pdf_sha1": "16b4ed929ce6", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02503', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '一片後散硬式散光隱形眼鏡，有3.00 D的鏡片散光設計在鏡片凹面時，被誘發出來的散光在角膜上 大約應該為何？', '["1.50 D", "2.00 D", "2.50 D", "3.00 D"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "81a695067d45", "answer_pdf_sha1": "16b4ed929ce6", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
